    finish_numeric_count = 0
    calculate_count = 0
    answer_count = 0
    truncation_count = 0
    parser_error_count = 0
    malformed_tool_count = 0
    synthetic_finish_count = 0
    calculator_error_count = 0
    symbolic_calculator_error_count = 0
    successful_calculate_count = 0
